package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVFormat.Predefined;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

public class CSVFormatTest {

    @Test
    void testValueOf_withValidFormatName() {
        try (MockedStatic<CSVFormat.Predefined> mockedPredefined = Mockito.mockStatic(CSVFormat.Predefined.class)) {
            CSVFormat expectedFormat = CSVFormat.DEFAULT;
            CSVFormat.Predefined predefinedMock = Mockito.mock(CSVFormat.Predefined.class);

            mockedPredefined.when(() -> CSVFormat.Predefined.valueOf("DEFAULT")).thenReturn(predefinedMock);
            Mockito.when(predefinedMock.getFormat()).thenReturn(expectedFormat);

            CSVFormat actualFormat = CSVFormat.valueOf("DEFAULT");

            assertSame(expectedFormat, actualFormat);
            mockedPredefined.verify(() -> CSVFormat.Predefined.valueOf("DEFAULT"));
            Mockito.verify(predefinedMock).getFormat();
        }
    }

    @Test
    void testValueOf_withNullFormatName_shouldThrowNullPointerException() {
        assertThrows(NullPointerException.class, () -> CSVFormat.valueOf(null));
    }

    @Test
    void testValueOf_withUnknownFormatName_shouldThrowIllegalArgumentException() {
        try (MockedStatic<CSVFormat.Predefined> mockedPredefined = Mockito.mockStatic(CSVFormat.Predefined.class)) {
            mockedPredefined.when(() -> CSVFormat.Predefined.valueOf("UNKNOWN"))
                    .thenThrow(new IllegalArgumentException("No enum constant"));

            IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> CSVFormat.valueOf("UNKNOWN"));
            assertTrue(ex.getMessage().contains("No enum constant"));
        }
    }
}
